+        "ready_label",
+    );
+    assert!(
+        ready_core.status.success(),
+        "ready label failed: {}",
+        ready_core.stderr
+    );
+    let ready_core_payload = extract_json_payload(&ready_core.stdout);
+    let ready_core_json: Vec<Value> =
